SELECT c.charge_no, c.charge_dt, c.charge_amt, m.member_no, m.region_no, p.payment_no, p.payment_dt FROM charge AS c JOIN member AS m ON c.member_no = m.member_no LEFT JOIN payment AS p ON c.member_no = p.member_no JOIN corporation AS co ON m.corp_no = co.corp_no WHERE (co.region_no IN (1, 2, 3, 4)) AND (strftime('%Y', c.charge_dt) = strftime('%Y', p.payment_dt) OR p.payment_no IS NULL)
